package com.example.mfa.MfaApplication.config;

import com.example.mfa.MfaApplication.security.MfaAuthenticationSuccessHandler;
import com.example.mfa.MfaApplication.security.CustomUserDetailsService;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private final CustomUserDetailsService customUserDetailsService;
    private final MfaAuthenticationSuccessHandler mfaAuthenticationSuccessHandler;

    public SecurityConfig(CustomUserDetailsService customUserDetailsService,
                          MfaAuthenticationSuccessHandler mfaAuthenticationSuccessHandler) {
        this.customUserDetailsService = customUserDetailsService;
        this.mfaAuthenticationSuccessHandler = mfaAuthenticationSuccessHandler;
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public DaoAuthenticationProvider authenticationProvider() {
        DaoAuthenticationProvider authProvider = new DaoAuthenticationProvider();
        authProvider.setUserDetailsService(customUserDetailsService);
        authProvider.setPasswordEncoder(passwordEncoder());
        return authProvider;
    }

    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration authConfig) throws Exception {
        return authConfig.getAuthenticationManager();
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/register", "/css/**", "/webjars/**", "/login", "/mfa-challenge", "/error").permitAll()
                        .anyRequest().authenticated()
                )
                .formLogin(form -> form
                        .loginPage("/login")
                        .successHandler(mfaAuthenticationSuccessHandler) // Our custom handler for MFA step
                        .permitAll()
                )
                .logout(logout -> logout
                        .logoutUrl("/logout")
                        .logoutSuccessUrl("/login?logout")
                        .permitAll()
                )
                .authenticationProvider(authenticationProvider());

        return http.build();
    }
}

package com.example.mfa.MfaApplication.controller;

import com.example.mfa.MfaApplication.entity.User;
import com.example.mfa.MfaApplication.service.MfaService;
import com.example.mfa.MfaApplication.service.UserService;
import com.example.mfa.MfaApplication.web.dto.RegistrationDto;
import dev.samsonov.totp.QrCodeGenerator;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.WebAttributes;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ModelAttribute;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import java.util.List;
import java.util.Optional;

@Controller
public class AuthController {

    private final UserService userService;
    private final MfaService mfaService;
    private final PasswordEncoder passwordEncoder;

    public AuthController(UserService userService, MfaService mfaService, PasswordEncoder passwordEncoder) {
        this.userService = userService;
        this.mfaService = mfaService;
        this.passwordEncoder = passwordEncoder;
    }

    @GetMapping("/register")
    public String showRegistrationForm(Model model) {
        model.addAttribute("user", new RegistrationDto());
        return "register";
    }

    @PostMapping("/register")
    public String registerUserAccount(@ModelAttribute("user") RegistrationDto registrationDto, Model model) {
        if (userService.findByUsername(registrationDto.getUsername()).isPresent()) {
            model.addAttribute("error", "Username already exists.");
            return "register";
        }
        userService.save(registrationDto);
        return "redirect:/login?registered";
    }

    @GetMapping("/login")
    public String login(Model model, HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        String errorMessage = null;
        if (session != null) {
            Exception ex = (Exception) session.getAttribute(WebAttributes.AUTHENTICATION_EXCEPTION);
            if (ex != null) {
                errorMessage = ex.getMessage();
            }
        }
        if (errorMessage != null) {
            model.addAttribute("error", errorMessage);
        }
        return "login";
    }

    @GetMapping("/mfa-challenge")
    public String showMfaChallenge(Model model, HttpSession session) {
        String username = (String) session.getAttribute("MFA_USERNAME");
        if (username == null) {
            // Should not happen if flow is correct, redirect to login
            return "redirect:/login";
        }
        model.addAttribute("username", username);
        return "mfa-challenge";
    }

    @PostMapping("/mfa-challenge")
    public String verifyMfaChallenge(@RequestParam("mfaCode") String mfaCode,
                                     @RequestParam("username") String username,
                                     HttpSession session,
                                     RedirectAttributes redirectAttributes) {
        Optional<User> userOptional = userService.findByUsername(username);

        if (userOptional.isEmpty() || !userOptional.get().isMfaEnabled()) {
            redirectAttributes.addFlashAttribute("error", "MFA not enabled for this user or user not found.");
            return "redirect:/login";
        }

        User user = userOptional.get();
        boolean mfaVerified = false;

        // Try validating TOTP
        if (user.getMfaSecret() != null && !user.getMfaSecret().isEmpty()) {
            mfaVerified = mfaService.verifyTotp(user.getMfaSecret(), mfaCode);
        }

        // If TOTP failed, try validating backup code
        if (!mfaVerified) {
            mfaVerified = mfaService.verifyBackupCode(user, mfaCode);
        }

        if (mfaVerified) {
            // Create a fully authenticated token and set it in the security context
            UserDetails userDetails = userService.loadUserByUsername(username);
            Authentication authentication = new UsernamePasswordAuthenticationToken(
                    userDetails, null, userDetails.getAuthorities());
            SecurityContextHolder.getContext().setAuthentication(authentication);
            session.removeAttribute("MFA_USERNAME"); // Clear the temporary username from session
            return "redirect:/home";
        } else {
            redirectAttributes.addFlashAttribute("error", "Invalid MFA code or backup code.");
            return "redirect:/mfa-challenge";
        }
    }

    @GetMapping("/mfa/setup")
    public String showMfaSetup(Model model, Authentication authentication) {
        String username = authentication.getName();
        Optional<User> userOptional = userService.findByUsername(username);
        if (userOptional.isEmpty()) {
            return "redirect:/login";
        }
        User user = userOptional.get();

        if (user.isMfaEnabled()) {
            // MFA is already enabled, show current status or option to disable/regenerate
            model.addAttribute("mfaEnabled", true);
            return "mfa-setup";
        }

        String secret = mfaService.generateMfaSecret();
        String qrCodeUrl = QrCodeGenerator.getTotpQrUri(secret, user.getUsername(), "MFA-App"); // Use an appropriate issuer name

        model.addAttribute("mfaEnabled", false);
        model.addAttribute("mfaSecret", secret);
        model.addAttribute("qrCodeUrl", qrCodeUrl);
        return "mfa-setup";
    }

    @PostMapping("/mfa/setup")
    public String setupMfa(@RequestParam("mfaSecret") String mfaSecret,
                           @RequestParam("mfaCode") String mfaCode,
                           Authentication authentication,
                           RedirectAttributes redirectAttributes,
                           Model model) {
        String username = authentication.getName();
        Optional<User> userOptional = userService.findByUsername(username);
        if (userOptional.isEmpty()) {
            return "redirect:/login";
        }
        User user = userOptional.get();

        if (mfaService.verifyTotp(mfaSecret, mfaCode)) {
            user.setMfaSecret(mfaSecret);
            user.setMfaEnabled(true);
            List<String> backupCodes = mfaService.generateAndSaveBackupCodes(user);
            userService.updateUser(user);

            model.addAttribute("backupCodes", backupCodes);
            return "mfa-backup-codes"; // Redirect to a page to display backup codes
        } else {
            redirectAttributes.addFlashAttribute("error", "Invalid TOTP code. Please try again.");
            return "redirect:/mfa/setup";
        }
    }

    @PostMapping("/mfa/disable")
    public String disableMfa(Authentication authentication, RedirectAttributes redirectAttributes) {
        String username = authentication.getName();
        Optional<User> userOptional = userService.findByUsername(username);
        if (userOptional.isEmpty()) {
            redirectAttributes.addFlashAttribute("error", "User not found.");
            return "redirect:/home";
        }

        User user = userOptional.get();
        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        mfaService.clearBackupCodes(user); // Clear all backup codes
        userService.updateUser(user);

        redirectAttributes.addFlashAttribute("message", "MFA has been disabled.");
        return "redirect:/home";
    }

    @GetMapping("/mfa/backup-codes")
    public String showBackupCodes(Model model, Authentication authentication) {
        String username = authentication.getName();
        Optional<User> userOptional = userService.findByUsername(username);
        if (userOptional.isEmpty() || !userOptional.get().isMfaEnabled()) {
            return "redirect:/home"; // Only show if MFA is enabled
        }
        User user = userOptional.get();
        List<String> activeBackupCodes = mfaService.getActiveBackupCodes(user);
        model.addAttribute("backupCodes", activeBackupCodes);
        return "mfa-backup-codes";
    }
}

