package com.example.mfa.MfaApplication.entity;

import jakarta.persistence.*;
import java.util.HashSet;
import java.util.Set;

@Entity
@Table(name = "users")
public class User {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(unique = true, nullable = false)
    private String username;

    @Column(nullable = false)
    private String password;

    private String mfaSecret; // Base32 encoded secret for TOTP
    private boolean mfaEnabled = false;

    private boolean enabled = true; // For account activation/deactivation

    @OneToMany(mappedBy = "user", cascade = CascadeType.ALL, orphanRemoval = true)
    private Set<BackupCode> backupCodes = new HashSet<>();

    public User() {
    }

    public User(String username, String password) {
        this.username = username;
        this.password = password;
    }

    // Getters and Setters
    public Long getId() {
        return id;
    }

    public void setId(Long id) {
        this.id = id;
    }

    public String getUsername() {
        return username;
    }

    public void setUsername(String username) {
        this.username = username;
    }

    public String getPassword() {
        return password;
    }

    public void setPassword(String password) {
        this.password = password;
    }

    public String getMfaSecret() {
        return mfaSecret;
    }

    public void setMfaSecret(String mfaSecret) {
        this.mfaSecret = mfaSecret;
    }

    public boolean isMfaEnabled() {
        return mfaEnabled;
    }

    public void setMfaEnabled(boolean mfaEnabled) {
        this.mfaEnabled = mfaEnabled;
    }

    public boolean isEnabled() {
        return enabled;
    }

    public void setEnabled(boolean enabled) {
        this.enabled = enabled;
    }

    public Set<BackupCode> getBackupCodes() {
        return backupCodes;
    }

    public void setBackupCodes(Set<BackupCode> backupCodes) {
        this.backupCodes = backupCodes;
    }

    public void addBackupCode(BackupCode backupCode) {
        this.backupCodes.add(backupCode);
        backupCode.setUser(this);
    }

    public void removeBackupCode(BackupCode backupCode) {
        this.backupCodes.remove(backupCode);
        backupCode.setUser(null);
    }
}

