package com.example.mfa.MfaApplication.security;

import com.example.mfa.MfaApplication.entity.User;
import com.example.mfa.MfaApplication.service.UserService;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.stereotype.Service;

import java.util.Collections;
import java.util.Optional;

@Service
public class CustomUserDetailsService implements UserDetailsService {

    private final UserService userService;

    public CustomUserDetailsService(UserService userService) {
        this.userService = userService;
    }

    @Override
    public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
        Optional<User> userOptional = userService.findByUsername(username);

        if (userOptional.isEmpty()) {
            throw new UsernameNotFoundException("User not found with username: " + username);
        }

        User user = userOptional.get();

        return new org.springframework.security.core.userdetails.User(
                user.getUsername(),
                user.getPassword(),
                user.isEnabled(),
                true,
                true,
                true,
                Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER")));
    }
}

package com.example.mfa.MfaApplication.security;

import com.example.mfa.MfaApplication.entity.User;
import com.example.mfa.MfaApplication.service.UserService;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;
import java.util.Optional;

@Component
public class MfaAuthenticationSuccessHandler implements AuthenticationSuccessHandler {

    private final UserService userService;

    public MfaAuthenticationSuccessHandler(UserService userService) {
        this.userService = userService;
    }

    @Override
    public void onAuthenticationSuccess(HttpServletRequest request, HttpServletResponse response, Authentication authentication) throws IOException, ServletException {
        UserDetails userDetails = (UserDetails) authentication.getPrincipal();
        Optional<User> userOptional = userService.findByUsername(userDetails.getUsername());

        if (userOptional.isPresent() && userOptional.get().isMfaEnabled()) {
            // User has MFA enabled, redirect to MFA challenge page
            HttpSession session = request.getSession();
            session.setAttribute("MFA_USERNAME", userDetails.getUsername()); // Store username temporarily
            response.sendRedirect("/mfa-challenge");
        } else {
            // No MFA or MFA not enabled, proceed to default success URL
            response.sendRedirect("/home");
        }
    }
}

package com.example.mfa.MfaApplication.service;

import com.example.mfa.MfaApplication.entity.BackupCode;
import com.example.mfa.MfaApplication.entity.User;
import com.example.mfa.MfaApplication.repository.BackupCodeRepository;
import com.example.mfa.MfaApplication.repository.UserRepository;
import dev.samsonov.totp.TotpValidator;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.List;
import java.util.Base64;
import java.util.Optional;
import java.util.stream.Collectors;

@Service
public class MfaService {

    private static final int BACKUP_CODE_LENGTH = 10;
    private static final int NUM_BACKUP_CODES = 10;
    private static final String CHAR_LOWER = "abcdefghijklmnopqrstuvwxyz";
    private static final String CHAR_UPPER = CHAR_LOWER.toUpperCase();
    private static final String NUMBER = "0123456789";
    private static final String DATA_FOR_RANDOM_STRING = CHAR_LOWER + CHAR_UPPER + NUMBER;
    private static SecureRandom random = new SecureRandom();

    private final TotpValidator totpValidator;
    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository; // To save user with backup codes
    private final PasswordEncoder passwordEncoder; // For hashing backup codes

    public MfaService(TotpValidator totpValidator, BackupCodeRepository backupCodeRepository,
                      UserRepository userRepository, PasswordEncoder passwordEncoder) {
        this.totpValidator = totpValidator;
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public String generateMfaSecret() {
        byte[] buffer = new byte[10]; // 10 bytes for 160-bit key, as recommended by RFC6238
        random.nextBytes(buffer);
        return Base32.encode(buffer);
    }

    public boolean verifyTotp(String secret, String code) {
        return totpValidator.isValid(secret, code);
    }

    @Transactional
    public List<String> generateAndSaveBackupCodes(User user) {
        // Clear existing backup codes if any
        clearBackupCodes(user);

        List<String> rawBackupCodes = new ArrayList<>();
        for (int i = 0; i < NUM_BACKUP_CODES; i++) {
            String rawCode = generateRandomBackupCode(BACKUP_CODE_LENGTH);
            String hashedCode = passwordEncoder.encode(rawCode); // Hash the code
            rawBackupCodes.add(rawCode);

            BackupCode backupCode = new BackupCode(hashedCode, user);
            user.addBackupCode(backupCode); // Add to user's set
        }
        userRepository.save(user); // Save user to cascade backup codes
        return rawBackupCodes;
    }

    @Transactional
    public boolean verifyBackupCode(User user, String submittedCode) {
        List<BackupCode> activeCodes = backupCodeRepository.findByUserAndUsedFalse(user);
        for (BackupCode code : activeCodes) {
            if (passwordEncoder.matches(submittedCode, code.getCodeHash())) {
                code.setUsed(true); // Mark as used
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    @Transactional
    public void clearBackupCodes(User user) {
        backupCodeRepository.deleteByUser(user);
        user.getBackupCodes().clear(); // Clear the collection on the entity
    }

    public List<String> getActiveBackupCodes(User user) {
        // Note: This method should ideally not return raw backup codes
        // For display purposes, it would only be shown immediately after generation.
        // If retrieving later, consider security implications or omit showing them.
        // For this example, we'll return an empty list if not during setup.
        // To truly retrieve, you'd need to decrypt, which means storing plaintext/encrypted, which is risky.
        // For enterprise, you usually display once, tell user to save, and then they can only use them.
        return backupCodeRepository.findByUserAndUsedFalse(user)
                .stream()
                .map(code -> "******" + code.getId()) // Only show a masked identifier for existing codes
                .collect(Collectors.toList());
    }

    private String generateRandomBackupCode(int length) {
        StringBuilder sb = new StringBuilder(length);
        for (int i = 0; i < length; i++) {
            int rndCharAt = random.nextInt(DATA_FOR_RANDOM_STRING.length());
            char rndChar = DATA_FOR_RANDOM_STRING.charAt(rndCharAt);
            sb.append(rndChar);
        }
        return sb.toString();
    }

    // A simple Base32 encoder for the secret, as TotpValidator expects Base32
    // For a real app, use a dedicated library like Apache Commons Codec.
    private static class Base32 {
        private static final String ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

        public static String encode(final byte[] bytes) {
            int i = 0, index = 0, digit = 0;
            int currByte, nextByte;
            StringBuilder base32 = new StringBuilder((bytes.length + 7) * 8 / 5);

            while (i < bytes.length) {
                currByte = (bytes[i] >= 0) ? bytes[i] : (bytes[i] + 256); // unsign

                /* Is the current digit going to span a byte boundary? */
                if (index > 3) {
                    if ((i + 1) < bytes.length) {
                        nextByte = (bytes[i + 1] >= 0) ? bytes[i + 1] : (bytes[i + 1] + 256);
                    } else {
                        nextByte = 0;
                    }

                    digit = currByte & (0xFF >> index);
                    index = (index + 5) % 8;
                    digit <<= index;
                    digit |= nextByte >> (8 - index);
                    i++;
                } else {
                    digit = (currByte >> (8 - (index + 5))) & 0x1F;
                    index = (index + 5) % 8;
                    if (index == 0)
                        i++;
                }
                base32.append(ALPHABET.charAt(digit));
            }
            return base32.toString();
        }
    }
}

package com.example.mfa.MfaApplication.service;

import com.example.mfa.MfaApplication.entity.User;
import com.example.mfa.MfaApplication.repository.UserRepository;
import com.example.mfa.MfaApplication.web.dto.RegistrationDto;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.Optional;

@Service
public class UserService implements UserDetailsService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;

    public UserService(UserRepository userRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public Optional<User> findByUsername(String username) {
        return userRepository.findByUsername(username);
    }

    public User save(RegistrationDto registrationDto) {
        User user = new User(registrationDto.getUsername(), passwordEncoder.encode(registrationDto.getPassword()));
        return userRepository.save(user);
    }

    public User updateUser(User user) {
        return userRepository.save(user);
    }

    @Override
    public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
        return findByUsername(username)
                .map(user -> org.springframework.security.core.userdetails.User
                        .withUsername(user.getUsername())
                        .password(user.getPassword())
                        .roles("USER")
                        .disabled(!user.isEnabled())
                        .accountExpired(false)
                        .credentialsExpired(false)
                        .accountLocked(false)
                        .build())
                .orElseThrow(() -> new UsernameNotFoundException("User not found: " + username));
    }
}

package com.example.mfa.MfaApplication.web.dto;

public class RegistrationDto {
    private String username;
    private String password;

    public RegistrationDto() {
    }

    public RegistrationDto(String username, String password) {
        this.username = username;
        this.password = password;
    }

    // Getters and Setters
    public String getUsername() {
        return username;
    }

    public void setUsername(String username) {
        this.username = username;
    }

    public String getPassword() {
        return password;
    }

    public void setPassword(String password) {
        this.password = password;
    }
}

